// 00 환경설정
// 필요한 값은 이 노드 안에서만 수정하면 된다.
// Cloud Memo에서 X-N8N-TOKEN을 쓰는 경우 Webhook 노드에 Header Auth Credential을 별도로 지정한다.

const item = $input.first();

const config = {
  workflowName: "JANG'S 아이디어 캐처",

  // Gemini
  // API Key는 n8n Credential: Google Gemini(PaLM) Api account(장승희-유료)에서 관리한다.
  // 이 노드에는 키를 직접 입력하지 않는다.
  geminiModel: 'gemini-2.5-flash',

  // Google Drive folders
  originalAudioFolderId: '1HuxWaQ9OTU0mhKC-H6S1t1l5AkIRYW-S', // 음성-카드노트

  // 장승희 위키 수집함으로 바로 들어 감 (장승희 위키/수집함)
  mdFolderId: '1K0YTpwaVhph1d-_DEhrcTfIPtXqj66H5', // JANG'S 아이디어 캐처

  // Gmail report
  reportEmailTo: 'moral_hazard@naver.com',

  // File naming
  audioPrefix: 'idea_audio',
  mdPrefix: 'idea_card',

  // 프롬프트: AI는 title/paragraphs/keywords만 JSON으로 반환한다.
  // MD 구조와 출처는 n8n 코드가 고정 생성한다.
  // 긴 음성 글쓰기를 과도하게 요약하지 않고, 말의 흐름을 살리는 방향이다.
  prompt: `너는 한국어 음성 글쓰기를 정리하는 보조 작가다.

사용자는 음성으로 글을 쓴다.
음성에는 "음", "어", 반복, 중단된 말, 되돌아간 설명, 주제 전환이 있을 수 있다.

목표:
끊긴 말과 생각의 공백은 말한 내용의 범위 안에서 자연스럽게 이어 문장화한다.
사용자가 말한 흐름, 논리, 예시, 감정의 결을 최대한 보존한다.
중언부언, 추임새, 반복, 말꼬리만 걷어내고 읽기 좋은 글로 정리한다.
AI가 임의로 검열하거나 절반으로 줄이지 않는다.
임의로 짧게 압축하지 않는다.

제목 규칙:
- title은 평범한 요약 제목으로 만들지 않는다.
- title은 실제 발화 속에서 나온 인상적인 표현, 핵심 문장, 힘 있는 워딩을 골라 만든다.
- 사용자가 직접 제목을 말하지 않았더라도, 말한 내용 안에서 가장 제목다운 표현을 찾아 25자 이내로 다듬는다.
- "아이디어 카드노트", "음성 메모", "생각 정리", "내용 요약", "아이디어 노트" 같은 일반 제목은 쓰지 않는다.
- 사용자가 말하지 않은 멋있는 표현을 새로 창작하지 않는다.
- 실제 워딩을 살리되 제목으로 읽히도록 조사나 어미 정도만 자연스럽게 다듬는다.

본문 규칙:
- paragraphs는 본문 문단 배열이다.
- 각 문단은 자연스러운 글 문장으로 작성한다.
- 사용자가 말한 순서와 흐름을 가능한 한 유지한다.
- 여러 생각이 이어지면 문단을 나누어 정리한다.
- 중언부언은 제거하되, 생각의 전개와 설명은 지나치게 줄이지 않는다.
- 사용자가 말하지 않은 사실, 사례, 결론을 새로 만들지 않는다.

출력 규칙:
- JSON만 반환한다.
- 마크다운, 코드블록, 설명문은 쓰지 않는다.
- keywords는 3~7개 배열로 만든다.

반환 형식:
{"title":"","paragraphs":[""],"keywords":[""]}`
};

return [{
  json: {
    ...item.json,
    _config: config,
  },
  binary: item.binary,
}];

// Cloud Memo multipart/form-data 입력 정리
// - body.title / body.content / body.memoId 수집
// - binary file_0, file_1 중 audio/* 우선 선택
// - 음성 원본은 sourceAudio binary field로 정규화
// - Gemini inlineData용 base64 생성

const item = $input.first();
const config = item.json._config || {};
const body = item.json.body || item.json || {};
const binary = item.binary || {};

const binaryKeys = Object.keys(binary);
const audioKey =
  binaryKeys.find((key) => (binary[key].mimeType || '').startsWith('audio/')) ||
  binaryKeys.find((key) => key.startsWith('file_')) ||
  binaryKeys[0];

if (!audioKey) {
  throw new Error('음성 파일이 없습니다. Cloud Memo에서 음성 녹음 파일이 file_0 형식으로 전송되었는지 확인하세요.');
}

const audioMeta = binary[audioKey];
const audioBuffer = await this.helpers.getBinaryDataBuffer(0, audioKey);
const audioBase64 = audioBuffer.toString('base64');

const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const yyyy = now.getFullYear();
const MM = pad(now.getMonth() + 1);
const dd = pad(now.getDate());
const hh = pad(now.getHours());
const mm = pad(now.getMinutes());
const ss = pad(now.getSeconds());

const dateText = `${yyyy}-${MM}-${dd} ${hh}:${mm}`;
const stamp = `${yyyy}${MM}${dd}_${hh}${mm}${ss}`;

const sourceTitle = String(body.title || '').trim();
const sourceContent = String(body.content || '').trim();
const memoId = String(body.memoId || '').trim();

const originalName = audioMeta.fileName || `voice_memo_${stamp}.webm`;
const extFromName = originalName.includes('.') ? originalName.split('.').pop() : 'webm';
const safeOriginalName = `${config.audioPrefix || 'idea_audio'}_${stamp}.${extFromName}`;

return [{
  json: {
    _config: config,
    sourceTitle,
    sourceContent,
    memoId,
    receivedAt: dateText,
    stamp,
    originalAudioFileName: safeOriginalName,
    originalAudioMimeType: audioMeta.mimeType || 'audio/webm',
    originalAudioSize: audioMeta.fileSize || audioBuffer.length,
    audioBase64,
  },
  binary: {
    sourceAudio: {
      ...audioMeta,
      fileName: safeOriginalName,
    },
  },
}];

// Google Drive 저장 결과 + 01 입력 정리 결과를 결합해 Gemini 요청 JSON 생성
const drive = $input.first().json;
const prep = $items('01 입력 정리')[0].json;

const audioFileId = drive.id || drive.fileId || '';
const audioDriveLink = drive.webViewLink || (audioFileId ? `https://drive.google.com/file/d/${audioFileId}/view?usp=drivesdk` : '');

const config = prep._config || {};

const sourceText = [
  prep.sourceTitle ? `사용자 입력 제목: ${prep.sourceTitle}` : '',
  prep.sourceContent ? `사용자 입력 메모: ${prep.sourceContent}` : '',
  `워크플로우명: ${config.workflowName || "JANG'S 아이디어 캐처"}`,
  `원본 음성 파일명: ${prep.originalAudioFileName}`,
  audioDriveLink ? `원본 음성 링크: ${audioDriveLink}` : '',
  `생성일시: ${prep.receivedAt}`,
].filter(Boolean).join('\n');

const instruction = `${config.prompt}\n\n참고 정보:\n${sourceText}`;

const geminiPayload = {
  contents: [
    {
      role: 'user',
      parts: [
        { text: instruction },
        {
          inlineData: {
            mimeType: prep.originalAudioMimeType || 'audio/webm',
            data: prep.audioBase64,
          },
        },
      ],
    },
  ],
  generationConfig: {
    temperature: 0.25,
    topP: 0.85,
    maxOutputTokens: 15000,
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'OBJECT',
      properties: {
        title: { type: 'STRING' },
        paragraphs: {
          type: 'ARRAY',
          items: { type: 'STRING' },
        },
        keywords: {
          type: 'ARRAY',
          items: { type: 'STRING' },
        },
      },
      required: ['title', 'paragraphs', 'keywords'],
    },
  },
};

return [{
  json: {
    ...prep,
    audioFileId,
    audioDriveLink,
    geminiPayload,
    // Gemini API Key는 HTTP Request 노드의 Google Gemini(PaLM) Credential이 주입한다.
    geminiUrl: `https://generativelanguage.googleapis.com/v1beta/models/${config.geminiModel}:generateContent`,
  },
}];

// Gemini 응답에서 title/paragraphs/keywords를 추출하고, n8n에서 표준 Markdown을 1회만 생성한다.
// 중요: JSON 파싱이 실패하면 억지로 MD를 만들지 않고 오류 처리한다.
// 원본 음성은 이미 Drive에 저장되어 있으므로 공통 오류 리포터로 확인 후 재처리한다.
const res = $input.first().json;
const meta = $items('03 Gemini 요청 구성')[0].json;
const config = meta._config || {};

const parts = res.candidates?.[0]?.content?.parts || [];
let raw = parts.map((p) => p.text || '').join('\n').trim();

if (!raw) {
  throw new Error('Gemini 응답에서 내용을 찾지 못했습니다. 원본 음성은 Drive에 저장되어 있으므로 재처리할 수 있습니다.');
}

const stripCodeFence = (text) => String(text)
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

const normalizeKeywords = (value) => {
  if (Array.isArray(value)) return value.map((v) => String(v).trim()).filter(Boolean).slice(0, 7);
  if (typeof value === 'string') return value.split(/[,\n]/).map((v) => v.replace(/^[-*]\s*/, '').trim()).filter(Boolean).slice(0, 7);
  return [];
};

const cleanText = (text) => String(text || '')
  .replace(/##\s*제목/gi, '')
  .replace(/##\s*내용/gi, '')
  .replace(/##\s*키워드(?: \(선택\))?/gi, '')
  .replace(/##\s*출처/gi, '')
  .replace(/원본 음성 파일명\s*[:：].*/gi, '')
  .replace(/원본 음성 링크\s*[:：].*/gi, '')
  .replace(/생성일시\s*[:：].*/gi, '')
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed = null;
try {
  parsed = JSON.parse(stripCodeFence(raw));
} catch (e) {
  throw new Error(`Gemini 응답 JSON 파싱 실패. 불완전한 MD를 생성하지 않고 중단합니다. 원본 음성 링크: ${meta.audioDriveLink || ''}\n\n원본 응답 앞부분:\n${raw.slice(0, 1200)}`);
}

const normalizeParagraphs = (value) => {
  if (Array.isArray(value)) {
    return value.map((p) => cleanText(p)).filter(Boolean);
  }

  // 구버전 응답 호환: content 문자열이 온 경우 문단으로 변환한다.
  if (typeof value === 'string') {
    const cleaned = cleanText(value);
    return cleaned
      .split(/\n{2,}/)
      .map((p) => p.trim())
      .filter(Boolean);
  }

  return [];
};

let paragraphs = normalizeParagraphs(parsed?.paragraphs);
if (paragraphs.length === 0 && parsed?.content) {
  paragraphs = normalizeParagraphs(parsed.content);
}

if (paragraphs.length === 0) {
  throw new Error(`Gemini 응답에 본문 paragraphs가 없습니다. 원본 음성 링크: ${meta.audioDriveLink || ''}`);
}

const genericTitlePatterns = [
  /^아이디어\s*카드노트$/i,
  /^아이디어\s*노트$/i,
  /^음성\s*메모$/i,
  /^음성\s*메모\s*정리$/i,
  /^생각\s*정리$/i,
  /^내용\s*요약$/i,
  /^메모\s*정리$/i,
  /^제목\s*없음$/i,
];

const sanitizeTitle = (s) => String(s || '')
  .replace(/[\\/:*?"<>|#\[\]\n\r\t]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const isGenericTitle = (title) => {
  const t = sanitizeTitle(title);
  return !t || genericTitlePatterns.some((re) => re.test(t));
};

const deriveTitleFromParagraphs = (paragraphList) => {
  const full = paragraphList.join(' ').replace(/\s+/g, ' ').trim();
  if (!full) return '';

  // 실제 발화 흐름에서 제목다운 문장을 우선 선택한다.
  const roughSentences = full
    .split(/(?<=[.!?])\s+|[。！？]\s*|\n+/)
    .map((s) => sanitizeTitle(s))
    .filter(Boolean);

  const preferred = roughSentences.find((s) =>
    s.length >= 8 && s.length <= 80 && /(해야|필요|중요|싫|좋|문제|핵심|방법|생각|글|작가|AI|잡아|놓치)/.test(s)
  ) || roughSentences.find((s) => s.length >= 8 && s.length <= 80) || full;

  return sanitizeTitle(preferred).slice(0, 25).trim();
};

let noteTitle = sanitizeTitle(parsed?.title);
if (isGenericTitle(noteTitle)) {
  const sourceTitle = sanitizeTitle(meta.sourceTitle);
  noteTitle = !isGenericTitle(sourceTitle) ? sourceTitle.slice(0, 25) : deriveTitleFromParagraphs(paragraphs);
}

if (!noteTitle) {
  throw new Error(`제목을 생성하지 못했습니다. 원본 음성 링크: ${meta.audioDriveLink || ''}`);
}

const content = paragraphs.join('\n\n');
let keywords = normalizeKeywords(parsed?.keywords);
if (keywords.length === 0) keywords = ['음성 글쓰기', '아이디어 정리'];

const keywordMd = keywords.map((k) => `- ${k}`).join('\n');
const workflowName = config.workflowName || "JANG'S 아이디어 캐처";

const md = `## 제목

${noteTitle}

## 내용

${content}

## 키워드 (선택)

${keywordMd}

## 출처

- 워크플로우: ${workflowName}
- 입력방식: Cloud Memo 음성 메모
- AI 모델: ${config.geminiModel || 'gemini-2.5-flash'}
- 원본 음성 파일명: ${meta.originalAudioFileName}
- 원본 음성 링크: ${meta.audioDriveLink}
- 생성일시: ${meta.receivedAt}
`;

const safeTitle = sanitizeTitle(noteTitle).slice(0, 40) || '아이디어 노트';
const mdFileName = `${config.mdPrefix || 'idea_card'}_${meta.stamp}_${safeTitle}.md`;

return [{
  json: {
    ...meta,
    noteTitle,
    paragraphs,
    keywords,
    md,
    mdFileName,
  },
}];

// Markdown 문자열을 Google Drive 업로드용 binary 파일로 변환
const item = $input.first().json;
const mdBuffer = Buffer.from(item.md, 'utf8');

return [{
  json: item,
  binary: {
    mdFile: {
      data: mdBuffer.toString('base64'),
      mimeType: 'text/markdown',
      fileName: item.mdFileName,
      fileExtension: 'md',
    },
  },
}];

// MD 저장 결과 + 이전 메타데이터 결합, 메일/응답 데이터 생성
// 이메일 리포팅 디자인: JANG'S AI Automation Email Frame Template v3.3 + Design.md v3.3 적용, 본문 구성 v1.93 반영, 전체 본문 메일 표시 수정
// 주의: Drive/Gemini/MD 생성 등 데이터 처리 로직은 변경하지 않고, 보고 메일의 제목/본문 구성만 표준화한다.
const drive = $input.first().json;
const parsed = $items('06 MD 파일 생성')[0].json;
const config = parsed._config || {};

const mdFileId = drive.id || drive.fileId || '';
const mdDriveLink = drive.webViewLink || (mdFileId ? `https://drive.google.com/file/d/${mdFileId}/view?usp=drivesdk` : '');

const workflowName = config.workflowName || "JANG'S 아이디어 캐처";

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const escapeAttr = escapeHtml;

const safeUrl = (value) => {
  const v = String(value || '').trim();
  if (/^https?:///i.test(v) || /^mailto:/i.test(v)) return v;
  return '#';
};

const plainText = (value) => String(value ?? '')
  .replace(/\s+/g, ' ')
  .trim();

const formatBytes = (bytes) => {
  const n = Number(bytes || 0);
  if (!Number.isFinite(n) || n <= 0) return '';
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  return `${(n / 1024 / 1024).toFixed(1)} MB`;
};

const sectionHeader = (label, title) => `
<div style="border-top:2px solid #0f766e;padding-top:12px;margin:30px 0 14px;text-align:left;">
  <p style="margin:0 0 6px;font-size:12px;line-height:1.4;color:#0f766e;font-weight:800;letter-spacing:0.08em;text-transform:uppercase;">
    ${escapeHtml(label)}
  </p>
  <h2 style="font-size:21px;line-height:1.4;margin:0;color:#111827;font-weight:800;letter-spacing:-0.02em;text-align:left;">
    ${escapeHtml(title)}
  </h2>
</div>`;

const roleLabel = (label) => `
<p style="margin:0 0 8px;text-align:left;">
  <span style="display:inline-block;padding:5px 10px;font-size:12px;line-height:1.35;color:#ffffff;background:#0f766e;border:1px solid #0f766e;border-radius:4px;font-weight:800;letter-spacing:-0.01em;">
    ${escapeHtml(label)}
  </span>
</p>`;

const paragraph = (text, extraStyle = '') => `
<p style="margin:0 0 13px;font-size:15px;line-height:1.78;color:#334155;text-align:left;${extraStyle}">
  ${escapeHtml(text)}
</p>`;

const linkLine = (label, url, linkText) => `
${roleLabel(label)}
<p style="margin:0 0 16px;text-align:left;">
  <a href="${escapeAttr(safeUrl(url))}" target="_blank" style="display:inline-block;color:#2563eb;text-decoration:underline;font-weight:700;word-break:break-word;overflow-wrap:anywhere;">
    ${escapeHtml(linkText)}
  </a>
</p>`;

const keywordsHtml = Array.isArray(parsed.keywords) && parsed.keywords.length
  ? `<p style="margin:4px 0 0;text-align:left;">${parsed.keywords.map((k) => `
      <span style="display:inline-block;margin:0 6px 6px 0;padding:4px 10px;font-size:12px;line-height:1.4;color:#0f766e;background:#f0fdfa;border:1px solid #99f6e4;border-radius:999px;">
        ${escapeHtml(k)}
      </span>`).join('')}</p>`
  : '';

const previewParagraphs = Array.isArray(parsed.paragraphs)
  ? parsed.paragraphs.map((p) => plainText(p)).filter(Boolean)
  : [];

// 생성된 본문 전체를 이메일에 표시한다.
// 이미 Gemini가 생성한 결과를 재사용하는 것이므로, 메일 본문에 전체 표시해도 추가 LLM 비용은 발생하지 않는다.
const previewHtml = previewParagraphs.map((p) => paragraph(p)).join('');
const previewMoreHtml = '';

const audioSizeText = formatBytes(parsed.originalAudioSize);
const metaLine = [
  `워크플로우: ${workflowName}`,
  `AI 모델: ${config.geminiModel || 'gemini-2.5-flash'}`,
  parsed.receivedAt ? `생성일시: ${parsed.receivedAt}` : '',
  audioSizeText ? `원본 음성 크기: ${audioSizeText}` : '',
].filter(Boolean).join(' · ');

const contentHtml = `
${sectionHeader('RESULT', '처리결과')}
${roleLabel('처리 완료')}
${paragraph('음성 메모를 아이디어 카드노트로 정리했습니다.')}
${roleLabel('노트 제목')}
<h3 style="font-size:18px;line-height:1.45;margin:0 0 10px;color:#111827;font-weight:800;letter-spacing:-0.01em;text-align:left;">
  ${escapeHtml(parsed.noteTitle)}
</h3>
${roleLabel('생성 파일명')}
${paragraph(parsed.mdFileName || '')}
<p style="margin:0 0 12px;font-size:13px;color:#6b7280;line-height:1.6;text-align:left;">
  ${escapeHtml(metaLine)}
</p>

${sectionHeader('IDEA', '캐치 아이디어 본문')}
${previewHtml || paragraph('본문 문단을 찾지 못했습니다. MD 지식노트 파일에서 확인하세요.')}
${previewMoreHtml}

